// Проверяем, что файл загружен (binary data есть)
const item = $input.first();
const binary = item.binary;

if (!binary || Object.keys(binary).length === 0) {
  return [{ json: { valid: false, error: 'Файл не загружен. Прикрепите документ или изображение.' } }];
}

const key = Object.keys(binary)[0];
const info = binary[key];

return [{
  json: {
    valid: true,
    binaryKey: key,
    fileName: info.fileName || 'unknown',
    mimeType: info.mimeType || 'unknown'
  },
  binary: binary
}];

// Извлекаем текст из ответа OCR.
// Разные OCR-движки возвращают текст в разных полях.
try {
  const data = $input.first().json;

  // Если OCR вернул ошибку (onError: continueRegularOutput)
  if (data.error) {
    const msg = typeof data.error === 'string' ? data.error : (data.error.message || JSON.stringify(data.error));
    return [{ json: { has_text: false, error: 'OCR ошибка: ' + msg } }];
  }

  let text = '';

  // Пробуем типичные форматы ответа OCR
  if (typeof data === 'string') {
    text = data;
  } else if (data.text && typeof data.text === 'string') {
    text = data.text;
  } else if (data.result && typeof data.result === 'string') {
    text = data.result;
  } else if (data.result && data.result.text) {
    text = data.result.text;
  } else if (data.content && typeof data.content === 'string') {
    text = data.content;
  } else if (data.data && typeof data.data === 'string') {
    text = data.data;
  } else if (data.output && typeof data.output === 'string') {
    text = data.output;
  } else {
    // Последний шанс — весь ответ как строка
    text = JSON.stringify(data);
  }

  text = text.trim();

  if (!text || text === '{}' || text === '[]' || text === 'null' || text.length < 3) {
    return [{ json: { has_text: false, error: 'OCR не смог распознать текст в документе. Попробуйте другой файл или более чёткий скан.' } }];
  }

  // Ограничиваем длину текста (GigaChat имеет лимит контекста)
  if (text.length > 15000) {
    text = text.substring(0, 15000) + '\n[...текст обрезан — слишком длинный документ]';
  }

  return [{ json: { has_text: true, ocr_text: text } }];

} catch (e) {
  return [{ json: { has_text: false, error: 'Ошибка обработки ответа OCR: ' + e.message } }];
}

// Безопасно извлекаем ответ GigaChat
try {
  const raw = $input.first().json;

  // Проверяем, не было ли ошибки GigaChat
  if (raw.error) {
    return [{ json: { response_text: 'Ошибка анализа документа. GigaChat недоступен. Попробуйте ещё раз.' } }];
  }

  const text = raw.output[0].content[0].text;

  if (!text || text.trim().length === 0) {
    return [{ json: { response_text: 'GigaChat вернул пустой ответ. Попробуйте загрузить файл ещё раз.' } }];
  }

  return [{ json: { response_text: text.trim() } }];

} catch (e) {
  return [{ json: { response_text: 'Ошибка при обработке ответа GigaChat. Попробуйте загрузить файл ещё раз.' } }];
}
